nodes.comment:
desc = Authenticate customer and validate JWT token. 
inputs = [ 
{"name":"authToken","type":"JWT","source":"request"} 
] 
outputs = [ 
{"name":"customerId","type":"UUID","target":"context"} 
] 
exceptions = ["Unauthorized","Forbidden"] 
preCondition = valid_jwt_format 
postCondition = customer_authenticated

desc = Publish StatementReady domain event 
inputs = [ 
{"name":"statementId","type":"UUID","source":"context"}, 
{"name":"downloadUrl","type":"String","source":"context"} 
] 
outputs = [ 
{"name":"eventPublished","type":"bool","target":"event"} 
] 
exceptions = ["EventPublishFailed"] 
sideEffects = true

desc = Store document to object storage and update job status. 
inputs = [ 
{"name":"statementId","type":"UUID","source":"context"}, 
{"name":"statementDocument","type":"byte[]","source":"context"} 
] 
outputs = [ 
{"name":"downloadUrl","type":"String","target":"context"}, 
{"name":"jobStatus","type":"String","target":"context"} 
] 
exceptions = ["StorageUnavailable"] 
preCondition = document_rendered 
postCondition = statement_stored_and_job_completed 
sideEffects = true 
retryPolicy = {"maxAttempts":3,"backoffMs":500,"retryOn":["Timeout","502","503","StorageUnavailable"],"onRetryExhausted": "throw_StorageUnavailable"}
